        // 6-factor formula: latency defaults to 0.5 for cold-start (no avg_response_ms)
        const expected =
            W_SUCCESS * expectedSuccess +
            W_CONF * 0 +
            W_TREND * 0.5 +
            W_SALIENCE * 1.0 +
