    }
  }

  get cacheSize(): number {
    return this.cache.size;
  }

  private setCache(key: string, scores: ScoredAction[]): void {
    // Evict oldest entry if at capacity
    if (this.cache.size >= MAX_CACHE_SIZE) {
      let oldestKey = '';
