/**
 * LayerInfinite MCP Server — gateway-proxy.ts
 * ══════════════════════════════════════════════════════════════
 * Core V2 Gateway Proxy. Intercepts tools/list (pre-reasoning
 * enrichment) and tools/call (proxy to upstream + auto-mode
 * rerouting). Natural language enrichment per mode — never
 * bracketed metadata.
 *
 * Phase 2 refactor: delegates enrichment to tool-enrichment.ts,
 * mode resolution to mode-manager.ts, score fetching to
 * score-fetcher.ts, and li_recommend to li-recommend-tool.ts.
 * ══════════════════════════════════════════════════════════════
 */

import type { GatewayConfig } from './config.js';
import type {
  EnrichedTool,
  EnrichmentContext,
  OutcomePayload,
  GatewayMode,
} from './types.js';
import type { LiApiClient, UpstreamMCPClient, UpstreamCallResult } from './rest-client.js';
import type { UpstreamRegistry } from './upstream-registry.js';
import { enqueueOutcome } from './fail-open.js';
import { enrichToolList } from './tool-enrichment.js';
import { ModeManager } from './mode-manager.js';
import { ScoreFetcher } from './enrichment/score-fetcher.js';
import { createLiRecommendTool, handleLiRecommend } from './li-recommend-tool.js';
import { generateDecisionId } from './decision-tracker.js';
export { generateDecisionId };
import { logger } from './logger.js';

const log = logger.forTool('gateway-proxy');

// ── Auto-mode reroute threshold ─────────────────────────────

const REROUTE_CONFIDENCE_THRESHOLD = 0.3;

// ══════════════════════════════════════════════════════════════
// GatewayProxy
// ══════════════════════════════════════════════════════════════

export class GatewayProxy {
  private readonly modeManager: ModeManager;
  private readonly scoreFetcher: ScoreFetcher;

  constructor(
    private readonly liApi: LiApiClient,
    private readonly upstreamClient: UpstreamMCPClient,
    private readonly registry: UpstreamRegistry,
    private readonly config: GatewayConfig,
  ) {
    this.modeManager = new ModeManager(config);
    this.scoreFetcher = new ScoreFetcher(liApi);
  }

  // ── tools/list handler ───────────────────────────────────

  async handleListTools(taskContext: {
    taskType: string;
    customerId: string;
    agentId: string;
  }): Promise<EnrichedTool[]> {
    const mode = this.modeManager.resolveMode(taskContext.taskType);

    try {
      const [rawTools, context] = await Promise.all([
        this.upstreamClient.listTools(),
        this.getEnrichmentContext(taskContext.taskType, taskContext.customerId, taskContext.agentId, mode),
      ]);

      const enriched = enrichToolList(rawTools, context);

      // Inject virtual li_recommend tool (only in non-bootstrap modes)
      if (mode !== 'bootstrap') {
        enriched.push(createLiRecommendTool());
      }

      // Sort: ranked first, then alphabetically
      enriched.sort((a, b) => {
        const rankA = a.annotations?.ranking ?? 999;
        const rankB = b.annotations?.ranking ?? 999;
        if (rankA !== rankB) return rankA - rankB;
        return a.name.localeCompare(b.name);
      });

      log.debug('tools/list enriched', {
        count: enriched.length,
        mode,
        taskType: taskContext.taskType,
      });

      return enriched;
    } catch (err) {
      log.error('tools/list failed', { error: err instanceof Error ? err.message : String(err) });
      // Degrade: return raw tools with no enrichment
      try {
        const rawTools = await this.upstreamClient.listTools();
        return rawTools.map((t) => ({
          name: t.name,
          description: t.description,
          inputSchema: t.inputSchema,
          upstreamName: t.upstreamName,
        }));
      } catch {
        return [];
      }
    }
  }

  // ── tools/call handler ───────────────────────────────────

  async handleCallTool(
    toolName: string,
    args: Record<string, unknown>,
    taskContext: { taskType: string; customerId: string; agentId: string },
  ): Promise<UpstreamCallResult> {
    const decisionId = generateDecisionId(taskContext.agentId);
    const mode = this.modeManager.resolveMode(taskContext.taskType);
    const startMs = Date.now();

    // Handle virtual li_recommend tool (delegated to li-recommend-tool.ts)
    if (toolName === 'li_recommend') {
      return handleLiRecommend(
        this.liApi,
        taskContext.taskType,
        taskContext.customerId,
        taskContext.agentId,
      );
    }

    // Determine which tool to execute (auto-mode may reroute)
    let executedAction = toolName;
    let originalAction = toolName;
    let rerouted = false;
    let enrichmentScores: Record<string, number> = {};

    if (mode === 'auto' && !this.config.shadowMode) {
      try {
        const [scores, policy] = await Promise.all([
          this.scoreFetcher.getScores(taskContext.taskType, taskContext.customerId, taskContext.agentId),
          this.liApi.getPolicyDecision(taskContext.taskType, taskContext.customerId, taskContext.agentId),
        ]);

        for (const s of scores) {
          enrichmentScores[s.actionName] = s.compositeScore;
        }

        if (
          policy &&
          policy.confidence >= REROUTE_CONFIDENCE_THRESHOLD &&
          policy.action !== toolName &&
          this.registry.isHealthy(this.resolveUpstream(policy.action))
        ) {
          originalAction = toolName;
          executedAction = policy.action;
          rerouted = true;
          log.info('Auto-mode reroute', {
            decisionId,
            from: toolName,
            to: policy.action,
            confidence: policy.confidence,
            reason: policy.reason,
          });
        }
      } catch {
        // Degrade — continue with original tool
      }
    }

    // Resolve upstream from tool name
    const upstreamName = this.resolveUpstream(executedAction);

    // Proxy to upstream
    const result = await this.upstreamClient.callTool(upstreamName, executedAction, args);

    // Fire-and-forget outcome logging
    const latencyMs = Date.now() - startMs;
    void this.logDecision({
      decisionId,
      agentId: taskContext.agentId,
      customerId: taskContext.customerId,
      taskType: taskContext.taskType,
      actionName: executedAction,
      upstreamName,
      originalAction,
      executedAction,
      mode,
      rerouted,
      enrichmentScores,
      latencyMs,
    });

    return result;
  }

  // ── Shutdown ─────────────────────────────────────────────

  async shutdown(): Promise<void> {
    this.registry.stopHealthChecks();
    log.info('Gateway proxy shut down');
  }

  // ── Private: enrichment context ──────────────────────────

  private async getEnrichmentContext(
    taskType: string,
    customerId: string,
    agentId: string,
    mode: GatewayMode,
  ): Promise<EnrichmentContext> {
    // Bootstrap mode — no enrichment needed
    if (mode === 'bootstrap') {
      return {
        taskType,
        customerId,
        agentId,
        mode,
        scores: [],
        policyDecision: null,
      };
    }

    try {
      const [scores, policyDecision] = await Promise.all([
        this.scoreFetcher.getScores(taskType, customerId, agentId),
        this.liApi.getPolicyDecision(taskType, customerId, agentId),
      ]);

      return { taskType, customerId, agentId, mode, scores, policyDecision };
    } catch (err) {
      log.warn('Enrichment context fetch failed — degrading to bootstrap-like', {
        error: err instanceof Error ? err.message : String(err),
      });
      return {
        taskType,
        customerId,
        agentId,
        mode,
        scores: [],
        policyDecision: null,
      };
    }
  }

  // ── Private: routing helpers ─────────────────────────────

  private resolveUpstream(toolName: string): string {
    const entries = this.registry.getAllUpstreams();

    // Match tool name to upstream by prefix convention:
    // "github_push_fix" → upstream named "github"
    // "database_query" → upstream named "database"
    const prefix = toolName.split('_')[0];
    if (prefix) {
      const matched = entries.find(
        (e) => e.server.name === prefix && this.registry.isHealthy(e.server.name),
      );
      if (matched) return matched.server.name;
    }

    // Fallback: first healthy upstream
    for (const entry of entries) {
      if (this.registry.isHealthy(entry.server.name)) return entry.server.name;
    }
    return entries[0]?.server.name ?? 'unknown';
  }

  private async logDecision(record: {
    decisionId: string;
    agentId: string;
    customerId: string;
    taskType: string;
    actionName: string;
    upstreamName: string;
    originalAction: string;
    executedAction: string;
    mode: GatewayMode;
    rerouted: boolean;
    enrichmentScores: Record<string, number>;
    latencyMs: number;
  }): Promise<void> {
    try {
      const payload: OutcomePayload = {
        decision_id: record.decisionId,
        agent_id: record.agentId,
        customer_id: record.customerId,
        task_type: record.taskType,
        action_name: record.actionName,
        upstream_name: record.upstreamName,
        original_action: record.originalAction,
        executed_action: record.executedAction,
        mode: record.mode,
        rerouted: record.rerouted,
        latency_ms: record.latencyMs,
        timestamp: new Date().toISOString(),
        ingestion_source: 'mcp',
        environment: this.config.environment,
      };

      const sent = await this.liApi.logOutcome(payload);
      if (!sent) {
        await enqueueOutcome(payload);
      }
    } catch {
      // Fire-and-forget — silent failure is acceptable
      log.debug('Outcome logging skipped (non-critical)');
    }
  }
}

/**
 * LayerInfinite MCP Server — enrichment/format-recommend.ts
 * ══════════════════════════════════════════════════════════════
 * Recommend-mode description formatting. Informational only —
 * provides historical success data with no directional guidance.
 * Appends enrichment as a single concatenated sentence.
 * ══════════════════════════════════════════════════════════════
 */

import type { ScoredAction } from '../types.js';

export function formatRecommendEnrichment(
  description: string,
  toolName: string,
  taskType: string,
  score: ScoredAction | null,
  rank: number | null,
): string {
  if (!score || score.sampleSize < 1) return description;

  const { successRate, sampleSize, trendLabel } = score;
  const pct = Math.round(successRate * 100);

  let enrichment: string;
  if (sampleSize < 3) {
    enrichment = `Insufficient historical data for ${toolName} on ${taskType} (${sampleSize} recorded outcomes).`;
  } else if (sampleSize < 10) {
    enrichment = `Historically, ${toolName} has resolved ${taskType} issues successfully ${pct}% of the time (limited data: ${sampleSize} outcomes).`;
  } else {
    enrichment = `Historically, ${toolName} has resolved ${taskType} issues successfully ${pct}% of the time (${sampleSize} recorded outcomes).`;
  }

  if (trendLabel && sampleSize >= 10) {
    enrichment += ` Success rate is ${formatTrend(trendLabel)}.`;
  }

  return `${description} ${enrichment}`;
}

function formatTrend(trendLabel: string): string {
  switch (trendLabel) {
    case 'strongly_improving': return 'improving significantly';
    case 'improving': return 'improving';
    case 'slightly_improving': return 'showing a slight positive trend';
    case 'stable': return 'stable';
    case 'slightly_declining': return 'showing a slight decline';
    case 'declining': return 'declining';
    case 'sharply_declining': return 'declining significantly';
    default: return '';
  }
}

/**
 * LayerInfinite MCP Server — decision-tracker.ts
 * ══════════════════════════════════════════════════════════════
 * Decision ID generation + episode tracking + buffer flush.
 * Replaces episode-tracker.ts (V1 redirect-loop prevention).
 *
 * Decision ID format: dec_{ts12}_{agent4}_{rand4}
 *   ts12    — base62-encoded timestamp (lexicographically sortable)
 *   agent4  — base62-encoded djb2 hash of agentId
 *   rand4   — 4 random base62 chars (collision prob < 10^-9 per ms)
 *
 * Buffer flushes every 5s to LI API. Disk queue fallback at
 * .li-queue/decisions.jsonl when API is unreachable.
 * ══════════════════════════════════════════════════════════════
 */

import { appendFileSync, mkdirSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import { randomBytes } from 'node:crypto';
import type { DecisionRecord, Episode } from './types.js';
import type { LiApiClient } from './rest-client.js';
import { logger } from './logger.js';

const log = logger.forTool('decision-tracker');

// ── Decision ID generation ──────────────────────────────────

const BASE62 = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
const FLUSH_INTERVAL_MS = 5_000;
const EPISODE_TTL_MS = 30 * 60 * 1000;
const MAX_COACHING_PER_EPISODE = 3;
const DISK_QUEUE_DIR = '.li-queue';
const DISK_QUEUE_FILE = 'decisions.jsonl';

function base62Encode(n: number, minLen: number): string {
  let s = '';
  let v = n;
  while (v > 0) {
    s = BASE62[v % 62] + s;
    v = Math.floor(v / 62);
  }
  return s.padStart(minLen, '0');
}

function djb2(s: string): number {
  let hash = 5381;
  for (let i = 0; i < s.length; i++) {
    hash = ((hash << 5) + hash) + s.charCodeAt(i);
    hash = hash >>> 0;
  }
  return hash;
}

function randomBase62(len: number): string {
  let s = '';
  const bytes = randomBytes(len);
  for (let i = 0; i < len; i++) {
    s += BASE62[bytes[i] % 62];
  }
  return s;
}

export function generateDecisionId(agentId: string): string {
  const ts12 = base62Encode(Date.now(), 12);
  const agent4 = base62Encode(djb2(agentId), 4).slice(0, 4);
  const rand4 = randomBase62(4);
  return `dec_${ts12}_${agent4}_${rand4}`;
}

function generateEpisodeId(): string {
  const ts10 = base62Encode(Date.now(), 10);
  const rand6 = randomBase62(6);
  return `ep_${ts10}_${rand6}`;
}

// ══════════════════════════════════════════════════════════════
// DecisionTracker
// ══════════════════════════════════════════════════════════════

export class DecisionTracker {
  private readonly episodes = new Map<string, Episode>();
  private readonly buffer: DecisionRecord[] = [];
  private flushTimer: ReturnType<typeof setInterval> | null = null;
  private flushing = false;
  private queueDirEnsured = false;

  constructor(private readonly liApi: LiApiClient) {}

  // ── Episode management ───────────────────────────────────

  startEpisode(agentId: string, customerId: string): Episode {
    this.cleanExpiredEpisodes();

    const episode: Episode = {
      episodeId: generateEpisodeId(),
      agentId,
      sessionStart: new Date().toISOString(),
      decisions: [],
      coachingCount: 0,
    };

    this.episodes.set(episode.episodeId, episode);
    log.debug('Episode started', { episodeId: episode.episodeId, agentId, customerId });
    return episode;
  }

  getEpisode(episodeId: string): Episode | undefined {
    this.cleanExpiredEpisodes();
    return this.episodes.get(episodeId);
  }

  /** Record a coaching injection. Returns false if cap (3) already reached. */
  recordCoaching(episodeId: string): boolean {
    const episode = this.episodes.get(episodeId);
    if (!episode) return false;
    if (episode.coachingCount >= MAX_COACHING_PER_EPISODE) return false;
    episode.coachingCount++;
    return true;
  }

  canCoach(episodeId: string): boolean {
    const episode = this.episodes.get(episodeId);
    if (!episode) return true; // No episode yet — coaching is allowed
    return episode.coachingCount < MAX_COACHING_PER_EPISODE;
  }

  // ── Decision recording ───────────────────────────────────

  recordDecision(record: DecisionRecord): void {
    this.buffer.push(record);

    // Link to episode
    if (this.episodes.size > 0) {
      // Find the most recent episode for this agent
      let latest: Episode | undefined;
      for (const ep of this.episodes.values()) {
        if (ep.agentId === record.agentId) {
          if (!latest || ep.sessionStart > latest.sessionStart) {
            latest = ep;
          }
        }
      }
      if (latest) {
        latest.decisions.push(record.decisionId);
      }
    }

    // Append to disk queue for durability
    this.appendToDiskQueue(record);

    log.debug('Decision recorded', { decisionId: record.decisionId });
  }

  // ── Flush ────────────────────────────────────────────────

  async flushBuffer(): Promise<void> {
    if (this.buffer.length === 0 || this.flushing) return;

    this.flushing = true;
    const batch = this.buffer.splice(0);

    try {
      // Send each decision's outcome to LI API
      for (const record of batch) {
        const sent = await this.liApi.logOutcome({
          decision_id: record.decisionId,
          agent_id: record.agentId,
          customer_id: record.customerId,
          task_type: record.taskType,
          action_name: record.actionName,
          upstream_name: record.upstreamName,
          original_action: record.originalAction,
          executed_action: record.executedAction,
          mode: record.mode,
          rerouted: record.rerouted,
          latency_ms: 0,
          timestamp: record.timestamp,
          ingestion_source: 'mcp',
          environment: 'production',
        });

        if (!sent) {
          // Re-queue on failure
          this.buffer.push(record);
        }
      }
    } catch (err) {
      log.warn('Buffer flush failed — re-queuing', {
        count: batch.length,
        error: err instanceof Error ? err.message : String(err),
      });
      this.buffer.push(...batch);
    } finally {
      this.flushing = false;
    }
  }

  startFlushTimer(): void {
    if (this.flushTimer) return;
    this.flushTimer = setInterval(() => {
      void this.flushBuffer();
    }, FLUSH_INTERVAL_MS);
  }

  stopFlushTimer(): void {
    if (this.flushTimer) {
      clearInterval(this.flushTimer);
      this.flushTimer = null;
    }
  }

  // ── Stats ────────────────────────────────────────────────

  get bufferSize(): number {
    return this.buffer.length;
  }

  get episodeCount(): number {
    this.cleanExpiredEpisodes();
    return this.episodes.size;
  }

  // ── Private ──────────────────────────────────────────────

  private appendToDiskQueue(record: DecisionRecord): void {
    try {
      if (!this.queueDirEnsured) {
        if (!existsSync(DISK_QUEUE_DIR)) {
          mkdirSync(DISK_QUEUE_DIR, { recursive: true });
        }
        this.queueDirEnsured = true;
      }
      appendFileSync(
        join(DISK_QUEUE_DIR, DISK_QUEUE_FILE),
        JSON.stringify(record) + '\n',
        'utf-8',
      );
    } catch {
      // Disk queue is best-effort — silent failure is acceptable
    }
  }

  private cleanExpiredEpisodes(): void {
    const cutoff = Date.now() - EPISODE_TTL_MS;
    for (const [id, ep] of this.episodes) {
      if (new Date(ep.sessionStart).getTime() < cutoff) {
        this.episodes.delete(id);
      }
    }
  }
}

/**
 * LayerInfinite API — routes/model-history.ts
 * ══════════════════════════════════════════════════════════════
 * Admin routes for model version history, rollback, and pinning.
 *
 * GET    /v1/admin/model-history          — list versions
 * GET    /v1/admin/model-history/:v1/:v2  — diff two versions
 * POST   /v1/admin/model-history/rollback — rollback to a version
 * POST   /v1/admin/model-history/pin      — pin task_type to version
 * DELETE /v1/admin/model-history/pin      — remove a pin
 * ══════════════════════════════════════════════════════════════
 */

import { Hono } from 'hono';
import { z } from 'zod';
import {
  listModelVersions,
  getActiveVersion,
  rollbackModel,
  diffVersions,
  pinModelVersion,
  unpinModelVersion,
  listPins,
} from '../lib/model-versioning.js';

export const modelHistoryRouter = new Hono();

// ── GET / — list versions ─────────────────────────────────────

modelHistoryRouter.get('/', async (c) => {
  const customerId = c.get('customer_id') as string | undefined;
  if (!customerId) {
    return c.json({ error: 'Authentication required', code: 'UNAUTHORIZED' }, 401);
  }

  const limit = Math.min(100, Math.max(1, Number(c.req.query('limit')) || 20));

  try {
    const versions = await listModelVersions(customerId, limit);
    const active = await getActiveVersion(customerId);
    const pins = await listPins(customerId);

    return c.json({
      customer_id: customerId,
      active_version: active?.version ?? null,
      version_count: versions.length,
      pins: pins.map((p) => ({
        task_type: p.task_type,
        pinned_version: p.pinned_version,
        pinned_at: p.pinned_at,
      })),
      versions: versions.map((v) => ({
        version: v.version,
        trained_at: v.trained_at,
        training_episodes: v.training_episodes,
        is_active: v.is_active,
        is_canary: v.is_canary,
        canary_traffic_pct: v.canary_traffic_pct,
        tier: v.tier,
      })),
    }, 200);
  } catch (err: any) {
    return c.json({ error: 'Failed to list versions', details: err.message, code: 'LIST_ERROR' }, 500);
  }
});

// ── GET /:fromVersion/:toVersion — diff ────────────────────────

modelHistoryRouter.get('/:fromVersion/:toVersion', async (c) => {
  const customerId = c.get('customer_id') as string | undefined;
  if (!customerId) {
    return c.json({ error: 'Authentication required', code: 'UNAUTHORIZED' }, 401);
  }

  const fromVersion = Number(c.req.param('fromVersion'));
  const toVersion = Number(c.req.param('toVersion'));

  if (!Number.isFinite(fromVersion) || !Number.isFinite(toVersion)) {
    return c.json({ error: 'Version parameters must be integers', code: 'VALIDATION_ERROR' }, 400);
  }

  try {
    const diff = await diffVersions(customerId, fromVersion, toVersion);
    if (!diff) {
      return c.json({ error: 'Could not compute diff — one or both versions not found', code: 'NOT_FOUND' }, 404);
    }

    return c.json(diff, 200);
  } catch (err: any) {
    return c.json({ error: 'Failed to compute diff', details: err.message, code: 'DIFF_ERROR' }, 500);
  }
});

// ── POST /rollback — rollback to a version ─────────────────────

const RollbackBody = z.object({
  customer_id: z.string().min(1),
  target_version: z.number().int().positive(),
});

modelHistoryRouter.post('/rollback', async (c) => {
  let body: z.infer<typeof RollbackBody>;
  try {
    body = RollbackBody.parse(await c.req.json());
  } catch (err: any) {
    const details = err.errors
      ? err.errors.map((e: any) => `${e.path.join('.')}: ${e.message}`).join(', ')
      : err.message;
    return c.json({ error: 'Invalid request body', details, code: 'VALIDATION_ERROR' }, 400);
  }

  try {
    const result = await rollbackModel(body.customer_id, body.target_version);

    if (!result.success) {
      return c.json({
        success: false,
        previous_version: result.previousVersion,
        attempted_version: body.target_version,
        error: result.error,
        code: 'ROLLBACK_FAILED',
      }, 400);
    }

    return c.json({
      success: true,
      previous_version: result.previousVersion,
      new_version: result.newVersion,
      message: `Rolled back from v${result.previousVersion} to v${result.newVersion}`,
    }, 200);
  } catch (err: any) {
    return c.json({ error: 'Rollback failed', details: err.message, code: 'ROLLBACK_ERROR' }, 500);
  }
});

// ── POST /pin — pin task_type to version ───────────────────────

const PinBody = z.object({
  customer_id: z.string().min(1),
  task_type: z.string().min(1).max(255),
  version: z.number().int().positive(),
  pinned_by: z.string().optional(),
});

modelHistoryRouter.post('/pin', async (c) => {
  let body: z.infer<typeof PinBody>;
  try {
    body = PinBody.parse(await c.req.json());
  } catch (err: any) {
    const details = err.errors
      ? err.errors.map((e: any) => `${e.path.join('.')}: ${e.message}`).join(', ')
      : err.message;
    return c.json({ error: 'Invalid request body', details, code: 'VALIDATION_ERROR' }, 400);
  }

  try {
    const pin = await pinModelVersion(body.customer_id, body.task_type, body.version, body.pinned_by);

    return c.json({
      pinned: true,
      task_type: pin.task_type,
      pinned_version: pin.pinned_version,
      pinned_at: pin.pinned_at,
      message: `Pinned "${body.task_type}" to v${body.version}`,
    }, 200);
  } catch (err: any) {
    return c.json({ error: 'Pin failed', details: err.message, code: 'PIN_ERROR' }, 500);
  }
});

// ── DELETE /pin — remove pin ───────────────────────────────────

const UnpinBody = z.object({
  customer_id: z.string().min(1),
  task_type: z.string().min(1).max(255),
});

modelHistoryRouter.delete('/pin', async (c) => {
  let body: z.infer<typeof UnpinBody>;
  try {
    body = UnpinBody.parse(await c.req.json());
  } catch (err: any) {
    const details = err.errors
      ? err.errors.map((e: any) => `${e.path.join('.')}: ${e.message}`).join(', ')
      : err.message;
    return c.json({ error: 'Invalid request body', details, code: 'VALIDATION_ERROR' }, 400);
  }

  try {
    const unpinned = await unpinModelVersion(body.customer_id, body.task_type);

    return c.json({
      unpinned,
      task_type: body.task_type,
      message: unpinned
        ? `Unpinned "${body.task_type}"`
        : `No pin found for "${body.task_type}"`,
    }, 200);
  } catch (err: any) {
    return c.json({ error: 'Unpin failed', details: err.message, code: 'UNPIN_ERROR' }, 500);
  }
});

/**
 * LayerInfinite MCP Server — tool-enrichment.ts
 * ══════════════════════════════════════════════════════════════
 * Enrichment engine. Orchestrates per-mode description formatting
 * for every tool returned by upstream servers. CRITICAL: inputSchema
 * is NEVER modified — only description is enriched.
 * ══════════════════════════════════════════════════════════════
 */

import type { EnrichedTool, EnrichmentContext, ScoredAction, GatewayMode } from './types.js';
import type { RawUpstreamTool } from './rest-client.js';
import { formatRecommendEnrichment } from './enrichment/format-recommend.js';
import { formatAssistEnrichment } from './enrichment/format-assist.js';
import type { AssistFormatContext } from './enrichment/format-assist.js';
import { formatAutoEnrichment } from './enrichment/format-auto.js';
import { logger } from './logger.js';

const log = logger.forTool('tool-enrichment');

/**
 * Enrich a list of upstream tools with historical outcome data.
 * Adds annotations (ranking, category) for internal use.
 * inputSchema is passed through unmodified.
 */
export function enrichToolList(
  tools: RawUpstreamTool[],
  context: EnrichmentContext,
): EnrichedTool[] {
  const { mode, scores, taskType } = context;

  // Build score lookup
  const scoreMap = new Map<string, ScoredAction>();
  for (const s of scores) {
    scoreMap.set(s.actionName, s);
  }

  // Rank by composite score descending
  const ranked = [...scores].sort((a, b) => b.compositeScore - a.compositeScore);
  const bestScore = ranked[0] ?? null;

  return tools.map((tool) => {
    const score = scoreMap.get(tool.name) ?? null;
    const rank = score
      ? ranked.findIndex((s) => s.actionName === tool.name) + 1
      : null;

    const enrichedDesc =
      mode === 'bootstrap'
        ? tool.description
        : enrichDescription(mode, tool, taskType, score, rank, tools.length, bestScore);

    return {
      name: tool.name,
      description: enrichedDesc,
      inputSchema: tool.inputSchema, // UNMODIFIED — passthrough from upstream
      upstreamName: tool.upstreamName,
      annotations: {
        ranking: rank ?? undefined,
        category: categorize(score),
      },
    };
  });
}

function enrichDescription(
  mode: GatewayMode,
  tool: RawUpstreamTool,
  taskType: string,
  score: ScoredAction | null,
  rank: number | null,
  totalTools: number,
  bestScore: ScoredAction | null,
): string {
  switch (mode) {
    case 'recommend':
      return formatRecommendEnrichment(
        tool.description,
        tool.name,
        taskType,
        score,
        rank,
      );

    case 'assist': {
      const ctx: AssistFormatContext = {
        toolName: tool.name,
        taskType,
        description: tool.description,
        score,
        rank,
        totalTools,
        bestScore,
      };
      return formatAssistEnrichment(ctx);
    }

    case 'auto':
      // Auto mode: descriptions unchanged — agent never knows LI exists.
      // Rerouting happens silently at the proxy level.
      return formatAutoEnrichment(tool.description);

    default:
      return tool.description;
  }
}

function categorize(
  score: ScoredAction | null,
): 'recommended' | 'neutral' | 'warning' | undefined {
  if (!score || score.sampleSize < 3) return undefined;
  if (score.compositeScore >= 0.7) return 'recommended';
  if (score.compositeScore >= 0.4) return 'neutral';
  return 'warning';
}

