985	// If a developer followed a recommendation (switched to a new action) and
986	// performance got WORSE, surface a warning alert in degradation_alert_events.
987	// Fire-and-forget - never throws, never blocks outcome logging.
988	export async function checkRecommendationRegression(
989	    customerId: string,
990	    agentId: string,
991	    actionId: string,
992	    actionName: string,
993	    taskName: string | null,
994	    finalSuccess: boolean,
995	): Promise<void> {
996	    if (!taskName) return;
997	    try {
998	        const { data: recentOutcomes, error } = await supabase
999	            .from('fact_outcomes')
1000	            .select('success, timestamp')
1001	            .eq('customer_id', customerId)
1002	            .eq('action_id', actionId)
1003	            .eq('task_name', taskName)
1004	            .eq('environment', 'production')
1005	            .order('timestamp', { ascending: false })
1006	            .limit(20);
1007	
1008	        if (error || !recentOutcomes || recentOutcomes.length < 10) return;
1009	
1010	        // Recent 10 outcomes success rate
1011	        const recent10 = recentOutcomes.slice(0, 10);
1012	        const recentRate = recent10.filter((o: any) => o.success).length / 10;
1013	
1014	        // Baseline: full 20-outcome rolling window
1015	        const baselineRate = recentOutcomes.filter((o: any) => o.success).length
1016	            / recentOutcomes.length;
1017	
1018	        // Regression threshold: recent 10 are 15%+ worse than 20-outcome baseline
1019	        const isRegression =
1020	            baselineRate > 0.1 &&
1021	            (baselineRate - recentRate) > 0.15;
1022	
1023	        if (!isRegression) return;
1024	
1025	        await supabase.from('degradation_alert_events').insert({
1026	            customer_id: customerId,
1027	            agent_id: agentId,
1028	            alert_type: 'recommendation_regression',
1029	            severity: 'warning',
1030	            message:
1031	                `Post-recommendation regression detected for action "${actionName}" ` +
1032	                `on task "${taskName}". ` +
1033	                `Recent 10-outcome rate: ${(recentRate * 100).toFixed(1)}% vs ` +
1034	                `baseline ${(baselineRate * 100).toFixed(1)}%. ` +
1035	                `This recommendation may not have improved performance. ` +
1036	                `Review in Dashboard -> Discrepancies.`,
1037	        });
1038	
1039	        console.warn('[log-outcome] recommendation_regression', {
1040	            customer_id: customerId,
1041	            agent_id: agentId,
1042	            action_name: actionName,
1043	            task_name: taskName,
1044	            recent_rate: recentRate,
1045	            baseline_rate: baselineRate,
1046	        });
1047	    } catch (err: any) {
