282	export function evaluateInconsistencyRules(params: {
283	    finalSuccess: boolean;
284	    outcomeScoreRaw: number | null;
285	    businessOutcome: string | null | undefined;
286	}): InconsistencyEvaluation {
287	    const lowThreshold = clamp01(
288	        Number(process.env.LI_INCONSISTENCY_THRESHOLD ?? 0.3)
289	    );
290	    const highThreshold = clamp01(
291	        Number(process.env.LI_INCONSISTENCY_HIGH_THRESHOLD ?? 0.7)
292	    );
293	
294	    if (params.finalSuccess && params.outcomeScoreRaw !== null && params.outcomeScoreRaw < lowThreshold) {
295	        return {
296	            isInconsistent: true,
297	            type: 'success_low_score',
298	            reason: `success=true but outcome_score_raw=${params.outcomeScoreRaw.toFixed(4)} < threshold ${lowThreshold.toFixed(4)}.`,
299	            ruleVersion: `v2:success_low_score:threshold=${lowThreshold.toFixed(4)}`,
300	        };
301	    }
302	    if (!params.finalSuccess && params.outcomeScoreRaw !== null && params.outcomeScoreRaw > highThreshold) {
303	        return {
304	            isInconsistent: true,
305	            type: 'failure_high_score',
306	            reason: `success=false but outcome_score_raw=${params.outcomeScoreRaw.toFixed(4)} > threshold ${highThreshold.toFixed(4)}.`,
307	            ruleVersion: `v2:failure_high_score:threshold=${highThreshold.toFixed(4)}`,
308	        };
309	    }
310	    if (params.finalSuccess && (params.businessOutcome === 'partial' || params.businessOutcome === 'failed')) {
311	        return {
312	            isInconsistent: true,
313	            type: 'success_business_conflict',
314	            reason: `success=true but business_outcome=${params.businessOutcome}.`,
315	            ruleVersion: 'v2:success_business_conflict',
316	        };
317	    }
318	    return { isInconsistent: false, type: null, reason: null, ruleVersion: null };
319	}
320	
321	function computeSalience(
322	    actionId: string,
323	    contextId: string,
324	    customerId: string,
