542	function isNearDuplicateCandidate(
543	    candidate: {
544	        outcome_score_raw: number | null;
545	        response_time_ms: number | null;
546	        error_code: string | null;
547	        business_outcome: string | null;
548	    },
549	    target: {
550	        outcomeScoreRaw: number | null;
551	        responseTimeMs: number | null;
552	        errorCode: string | null;
553	        businessOutcome: string | null;
554	    },
555	): boolean {
556	    const candidateError = normalizedTextToken(candidate.error_code);
557	    const targetError = normalizedTextToken(target.errorCode);
558	    if (candidateError !== targetError) return false;
559	
560	    const candidateOutcome = normalizedTextToken(candidate.business_outcome);
561	    const targetOutcome = normalizedTextToken(target.businessOutcome);
562	    if (candidateOutcome !== targetOutcome) return false;
563	
564	    if (typeof candidate.response_time_ms === 'number' && typeof target.responseTimeMs === 'number') {
565	        if (Math.abs(candidate.response_time_ms - target.responseTimeMs) > 250) {
566	            return false;
567	        }
568	    }
569	
570	    if (typeof candidate.outcome_score_raw === 'number' && typeof target.outcomeScoreRaw === 'number') {
571	        if (Math.abs(candidate.outcome_score_raw - target.outcomeScoreRaw) > 0.05) {
572	            return false;
573	        }
574	    }
575	
576	    return true;
577	}
