/**
 * llm-client.ts — NVIDIA API client for Qwen 3.5 122B.
 * Makes real LLM calls. No mocking.
 */

const NVIDIA_API_URL = 'https://integrate.api.nvidia.com/v1/chat/completions';
const MODEL = 'qwen/qwen3.5-122b-a10b';
const API_KEY = process.env.NVIDIA_API_KEY;
if (!API_KEY) {
  throw new Error('NVIDIA_API_KEY env var is required. Set it in your environment or .env file.');
}

export interface LLMResponse {
  content: string;
  latencyMs: number;
  tokensUsed: number;
}

/** Call the Qwen model with a system prompt and user prompt. */
export async function callLLM(systemPrompt: string, userPrompt: string): Promise<LLMResponse> {
  const start = Date.now();

  const res = await fetch(NVIDIA_API_URL, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      model: MODEL,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt },
      ],
      temperature: 0.3,
      max_tokens: 2048,
      chat_template_kwargs: { enable_thinking: false },
    }),
  });

  if (!res.ok) {
    const errorText = await res.text();
    throw new Error(`NVIDIA API error (${res.status}): ${errorText}`);
  }

  const data = await res.json() as any;
  const latencyMs = Date.now() - start;

  return {
    content: data.choices?.[0]?.message?.content ?? '',
    latencyMs,
    tokensUsed: data.usage?.total_tokens ?? 0,
  };
}

