  const { error: refreshErr } = await supabase.rpc('refresh_action_scores');
  if (refreshErr) {
    console.log(`   ❌ RPC failed: ${refreshErr.message}`);
    console.log('   Trying direct SQL via RPC...');
  } else {
    console.log('   ✅ refresh_action_scores RPC succeeded');
  }
  console.log();

  // 4. Check MV state AFTER refresh
  console.log('4️⃣  mv_action_scores AFTER REFRESH');
  const { data: mvAfter, error: mvAfterErr } = await supabase
    .from('mv_action_scores')
    .select('action_name, context_id, total_attempts, confidence, weighted_success_rate, raw_success_rate, view_refreshed_at')
    .limit(30);

  if (mvAfterErr) {
    console.log(`   ❌ MV query failed: ${mvAfterErr.message}`);
  } else if (!mvAfter || mvAfter.length === 0) {
    console.log('   ⚠️  MV is STILL EMPTY after refresh');
  } else {
    console.log(`   Rows in MV: ${mvAfter.length}`);
    for (const r of mvAfter) {
      console.log(`     ${(r.action_name ?? '???').padEnd(20)} | attempts: ${String(r.total_attempts).padEnd(4)} | conf: ${r.confidence} | raw_sr: ${r.raw_success_rate} | wsr: ${r.weighted_success_rate}`);
    }
  }
  console.log();

  // 5. Now hit get-scores API to see if scores differentiate
  console.log('5️⃣  GET SCORES AFTER MV REFRESH');
  const res = await fetch(`${LI_BASE_URL}/v1/get-scores?issue_type=sudoku_trivial&force_refresh=true`, {
    headers: { 'X-API-Key': LI_API_KEY, 'Content-Type': 'application/json' },
  });
  const scores = await res.json() as any;

  if (scores.ranked_actions) {
    console.log(`   cold_start: ${scores.cold_start}`);
    console.log(`   outcomes_needed: ${scores.outcomes_needed}`);
    console.log();
    for (const a of scores.ranked_actions) {
      console.log(`   ${a.action_name.padEnd(20)} | score: ${a.composite_score} | conf: ${a.confidence} | attempts: ${a.total_attempts} | cold: ${a.is_cold_start}`);
    }
  } else {
    console.log(`   Response:`, JSON.stringify(scores, null, 2).slice(0, 1000));
  }

  // 6. Check durable queue state
  console.log('\n6️⃣  DURABLE QUEUE STATE');
  const { data: queuePending } = await supabase
    .from('queue_outcome_ingress')
    .select('status, ingress_id', { count: 'exact', head: true })
    .eq('status', 'pending');
  const { data: queueDead } = await supabase
    .from('queue_outcome_ingress')
    .select('status, ingress_id', { count: 'exact', head: true })
    .eq('status', 'dead');
  const { data: queueFailed } = await supabase
    .from('queue_outcome_ingress')
    .select('status, ingress_id', { count: 'exact', head: true })
    .eq('status', 'failed');

  console.log(`   Pending: ${queuePending ?? '?'}`);
  console.log(`   Failed: ${queueFailed ?? '?'}`);
  console.log(`   Dead: ${queueDead ?? '?'}`);

  console.log('\n═══════════════════════════════════════════════════');
  console.log('  DONE');
  console.log('═══════════════════════════════════════════════════');
}

main().catch(err => {
  console.error('Fatal:', err);
  process.exit(1);
});

