22	const QUEUE_DIR = '.li-queue';
23	const CIRCUIT_BREAKER_THRESHOLD = 3;
24	const CIRCUIT_BREAKER_OPEN_MS = 60_000;
25	const MAX_QUEUE_RETRY_MS = 300_000; // 5 min max retry
26	const BASE_BACKOFF_MS = 1000;
27	
28	export function createFailOpenState(): FailOpenState {
29	  return {
30	    upstreamFailures: new Map(),
31	    circuitBreakerOpen: new Map(),
32	    lastHealthCheck: new Map(),
33	    totalRequests: 0,
34	    passthroughRequests: 0,
35	  };
36	}
