/**
 * LayerInfinite MCP Server — decision-tracker.ts
 * ══════════════════════════════════════════════════════════════
 * Decision ID generation + episode tracking + buffer flush.
 * Replaces episode-tracker.ts (V1 redirect-loop prevention).
 *
 * Decision ID format: dec_{ts12}_{agent4}_{rand4}
 *   ts12    — base62-encoded timestamp (lexicographically sortable)
 *   agent4  — base62-encoded djb2 hash of agentId
 *   rand4   — 4 random base62 chars (collision prob < 10^-9 per ms)
 *
 * Buffer flushes every 5s to LI API. Disk queue fallback at
 * .li-queue/decisions.jsonl when API is unreachable.
 * ══════════════════════════════════════════════════════════════
 */

import { appendFileSync, mkdirSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import { randomBytes } from 'node:crypto';
import type { DecisionRecord, Episode } from './types.js';
import type { LiApiClient } from './rest-client.js';
import { logger } from './logger.js';

const log = logger.forTool('decision-tracker');

// ── Decision ID generation ──────────────────────────────────

const BASE62 = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
const FLUSH_INTERVAL_MS = 5_000;
const EPISODE_TTL_MS = 30 * 60 * 1000;
const MAX_COACHING_PER_EPISODE = 3;
const DISK_QUEUE_DIR = '.li-queue';
const DISK_QUEUE_FILE = 'decisions.jsonl';

function base62Encode(n: number, minLen: number): string {
  let s = '';
  let v = n;
  while (v > 0) {
    s = BASE62[v % 62] + s;
    v = Math.floor(v / 62);
  }
  return s.padStart(minLen, '0');
}

function djb2(s: string): number {
  let hash = 5381;
  for (let i = 0; i < s.length; i++) {
    hash = ((hash << 5) + hash) + s.charCodeAt(i);
    hash = hash >>> 0;
  }
  return hash;
}

function randomBase62(len: number): string {
  let s = '';
  const bytes = randomBytes(len);
  for (let i = 0; i < len; i++) {
    s += BASE62[bytes[i] % 62];
  }
  return s;
}

export function generateDecisionId(agentId: string): string {
  const ts12 = base62Encode(Date.now(), 12);
  const agent4 = base62Encode(djb2(agentId), 4).slice(0, 4);
  const rand4 = randomBase62(4);
  return `dec_${ts12}_${agent4}_${rand4}`;
}

function generateEpisodeId(): string {
  const ts10 = base62Encode(Date.now(), 10);
  const rand6 = randomBase62(6);
  return `ep_${ts10}_${rand6}`;
}

// ══════════════════════════════════════════════════════════════
// DecisionTracker
// ══════════════════════════════════════════════════════════════

export class DecisionTracker {
  private readonly episodes = new Map<string, Episode>();
  private readonly buffer: DecisionRecord[] = [];
  private flushTimer: ReturnType<typeof setInterval> | null = null;
  private flushing = false;
  private queueDirEnsured = false;

  constructor(private readonly liApi: LiApiClient) {}

  // ── Episode management ───────────────────────────────────

  startEpisode(agentId: string, customerId: string): Episode {
    this.cleanExpiredEpisodes();

    const episode: Episode = {
      episodeId: generateEpisodeId(),
      agentId,
      sessionStart: new Date().toISOString(),
      decisions: [],
      coachingCount: 0,
    };

    this.episodes.set(episode.episodeId, episode);
    log.debug('Episode started', { episodeId: episode.episodeId, agentId, customerId });
    return episode;
  }

  getEpisode(episodeId: string): Episode | undefined {
    this.cleanExpiredEpisodes();
    return this.episodes.get(episodeId);
  }

  /** Record a coaching injection. Returns false if cap (3) already reached. */
  recordCoaching(episodeId: string): boolean {
    const episode = this.episodes.get(episodeId);
    if (!episode) return false;
    if (episode.coachingCount >= MAX_COACHING_PER_EPISODE) return false;
    episode.coachingCount++;
    return true;
  }

  canCoach(episodeId: string): boolean {
    const episode = this.episodes.get(episodeId);
    if (!episode) return true; // No episode yet — coaching is allowed
    return episode.coachingCount < MAX_COACHING_PER_EPISODE;
  }

  // ── Decision recording ───────────────────────────────────

  recordDecision(record: DecisionRecord): void {
    this.buffer.push(record);

    // Link to episode
    if (this.episodes.size > 0) {
      // Find the most recent episode for this agent
      let latest: Episode | undefined;
      for (const ep of this.episodes.values()) {
        if (ep.agentId === record.agentId) {
          if (!latest || ep.sessionStart > latest.sessionStart) {
            latest = ep;
          }
        }
      }
      if (latest) {
        latest.decisions.push(record.decisionId);
      }
    }

    // Append to disk queue for durability
    this.appendToDiskQueue(record);

    log.debug('Decision recorded', { decisionId: record.decisionId });
  }

  // ── Flush ────────────────────────────────────────────────

  async flushBuffer(): Promise<void> {
    if (this.buffer.length === 0 || this.flushing) return;

    this.flushing = true;
    const batch = this.buffer.splice(0);

    try {
      // Send each decision's outcome to LI API
      for (const record of batch) {
        const sent = await this.liApi.logOutcome({
          agent_id: record.agentId,
          customer_id: record.customerId,
          issue_type: record.taskType,
          action_name: record.actionName,
          upstream_name: record.upstreamName,
          original_action: record.originalAction,
          executed_action: record.executedAction,
          mode: record.mode,
          rerouted: record.rerouted,
          success: true,
          response_time_ms: 0,
          timestamp: record.timestamp,
          ingestion_source: 'mcp',
          environment: 'production',
        });

        if (!sent) {
          // Re-queue on failure
          this.buffer.push(record);
        }
      }
    } catch (err) {
      log.warn('Buffer flush failed — re-queuing', {
        count: batch.length,
        error: err instanceof Error ? err.message : String(err),
      });
      this.buffer.push(...batch);
    } finally {
      this.flushing = false;
    }
  }

  startFlushTimer(): void {
    if (this.flushTimer) return;
    this.flushTimer = setInterval(() => {
      void this.flushBuffer();
    }, FLUSH_INTERVAL_MS);
  }

  stopFlushTimer(): void {
    if (this.flushTimer) {
      clearInterval(this.flushTimer);
      this.flushTimer = null;
    }
  }

  // ── Stats ────────────────────────────────────────────────

  get bufferSize(): number {
    return this.buffer.length;
  }

  get episodeCount(): number {
    this.cleanExpiredEpisodes();
    return this.episodes.size;
  }

  // ── Private ──────────────────────────────────────────────

  private appendToDiskQueue(record: DecisionRecord): void {
    try {
      if (!this.queueDirEnsured) {
        if (!existsSync(DISK_QUEUE_DIR)) {
          mkdirSync(DISK_QUEUE_DIR, { recursive: true });
        }
        this.queueDirEnsured = true;
      }
      appendFileSync(
        join(DISK_QUEUE_DIR, DISK_QUEUE_FILE),
        JSON.stringify(record) + '\n',
        'utf-8',
      );
    } catch {
      // Disk queue is best-effort — silent failure is acceptable
    }
  }

  private cleanExpiredEpisodes(): void {
    const cutoff = Date.now() - EPISODE_TTL_MS;
    for (const [id, ep] of this.episodes) {
      if (new Date(ep.sessionStart).getTime() < cutoff) {
        this.episodes.delete(id);
      }
    }
  }
}

/**
 * LayerInfinite MCP Server — gateway-proxy.ts
 * ══════════════════════════════════════════════════════════════
 * Core V2 Gateway Proxy. Intercepts tools/list (pre-reasoning
 * enrichment) and tools/call (proxy to upstream + auto-mode
 * rerouting). Natural language enrichment per mode — never
 * bracketed metadata.
 *
 * Phase 2 refactor: delegates enrichment to tool-enrichment.ts,
 * mode resolution to mode-manager.ts, score fetching to
 * score-fetcher.ts, and li_recommend to li-recommend-tool.ts.
 * ══════════════════════════════════════════════════════════════
 */

import type { GatewayConfig } from './config.js';
import type {
  EnrichedTool,
  EnrichmentContext,
  OutcomePayload,
  GatewayMode,
} from './types.js';
import type { LiApiClient, UpstreamMCPClient, UpstreamCallResult } from './rest-client.js';
import type { UpstreamRegistry } from './upstream-registry.js';
import { enqueueOutcome } from './fail-open.js';
import { enrichToolList } from './tool-enrichment.js';
import { ModeManager } from './mode-manager.js';
import { ScoreFetcher } from './enrichment/score-fetcher.js';
import { createLiRecommendTool, handleLiRecommend } from './li-recommend-tool.js';
import { generateDecisionId } from './decision-tracker.js';
export { generateDecisionId };
import { logger } from './logger.js';

const log = logger.forTool('gateway-proxy');

// ── Auto-mode reroute threshold ─────────────────────────────

const REROUTE_CONFIDENCE_THRESHOLD = 0.3;

// ══════════════════════════════════════════════════════════════
// GatewayProxy
// ══════════════════════════════════════════════════════════════

export class GatewayProxy {
  private readonly modeManager: ModeManager;
  private readonly scoreFetcher: ScoreFetcher;

  constructor(
    private readonly liApi: LiApiClient,
    private readonly upstreamClient: UpstreamMCPClient,
    private readonly registry: UpstreamRegistry,
    private readonly config: GatewayConfig,
  ) {
    this.modeManager = new ModeManager(config);
    this.scoreFetcher = new ScoreFetcher(liApi);
  }

  // ── tools/list handler ───────────────────────────────────

  async handleListTools(taskContext: {
    taskType: string;
    customerId: string;
    agentId: string;
  }): Promise<EnrichedTool[]> {
    const mode = this.modeManager.resolveMode(taskContext.taskType);

    try {
      const [rawTools, context] = await Promise.all([
        this.upstreamClient.listTools(),
        this.getEnrichmentContext(taskContext.taskType, taskContext.customerId, taskContext.agentId, mode),
      ]);

      const enriched = enrichToolList(rawTools, context);

      // Inject virtual li_recommend tool (only in non-bootstrap modes)
      if (mode !== 'bootstrap') {
        enriched.push(createLiRecommendTool());
      }

      // Sort: ranked first, then alphabetically
      enriched.sort((a, b) => {
        const rankA = a.annotations?.ranking ?? 999;
        const rankB = b.annotations?.ranking ?? 999;
        if (rankA !== rankB) return rankA - rankB;
        return a.name.localeCompare(b.name);
      });

      log.debug('tools/list enriched', {
        count: enriched.length,
        mode,
        taskType: taskContext.taskType,
      });

      return enriched;
    } catch (err) {
      log.error('tools/list failed', { error: err instanceof Error ? err.message : String(err) });
      // Degrade: return raw tools with no enrichment
      try {
        const rawTools = await this.upstreamClient.listTools();
        return rawTools.map((t) => ({
          name: t.name,
          description: t.description,
          inputSchema: t.inputSchema,
          upstreamName: t.upstreamName,
        }));
      } catch {
        return [];
      }
    }
  }

  // ── tools/call handler ───────────────────────────────────

  async handleCallTool(
    toolName: string,
    args: Record<string, unknown>,
    taskContext: { taskType: string; customerId: string; agentId: string },
  ): Promise<UpstreamCallResult> {
    const decisionId = generateDecisionId(taskContext.agentId);
    const mode = this.modeManager.resolveMode(taskContext.taskType);
    const startMs = Date.now();

    // Handle virtual li_recommend tool (delegated to li-recommend-tool.ts)
    if (toolName === 'li_recommend') {
      return handleLiRecommend(
        this.liApi,
        taskContext.taskType,
        taskContext.customerId,
        taskContext.agentId,
      );
    }

    // Determine which tool to execute (auto-mode may reroute)
    let executedAction = toolName;
    let originalAction = toolName;
    let rerouted = false;
    let enrichmentScores: Record<string, number> = {};

    if (mode === 'auto' && !this.config.shadowMode) {
      try {
        const [scores, policy] = await Promise.all([
          this.scoreFetcher.getScores(taskContext.taskType, taskContext.customerId, taskContext.agentId),
          this.liApi.getPolicyDecision(taskContext.taskType, taskContext.customerId, taskContext.agentId),
        ]);

        for (const s of scores) {
          enrichmentScores[s.actionName] = s.compositeScore;
        }

        if (
          policy &&
          policy.confidence >= REROUTE_CONFIDENCE_THRESHOLD &&
          policy.action !== toolName &&
          this.registry.isHealthy(this.resolveUpstream(policy.action))
        ) {
          originalAction = toolName;
          executedAction = policy.action;
          rerouted = true;
          log.info('Auto-mode reroute', {
            decisionId,
            from: toolName,
            to: policy.action,
            confidence: policy.confidence,
            reason: policy.reason,
          });
        }
      } catch {
        // Degrade — continue with original tool
      }
    }

    // Resolve upstream from tool name
    const upstreamName = this.resolveUpstream(executedAction);

    // Proxy to upstream
    const result = await this.upstreamClient.callTool(upstreamName, executedAction, args);

    // Fire-and-forget outcome logging
    const latencyMs = Date.now() - startMs;
    void this.logDecision({
      decisionId,
      agentId: taskContext.agentId,
      customerId: taskContext.customerId,
      taskType: taskContext.taskType,
      actionName: executedAction,
      upstreamName,
      originalAction,
      executedAction,
      mode,
      rerouted,
      enrichmentScores,
      latencyMs,
    });

    return result;
  }

  // ── Shutdown ─────────────────────────────────────────────

  async shutdown(): Promise<void> {
    this.registry.stopHealthChecks();
    log.info('Gateway proxy shut down');
  }

  // ── Private: enrichment context ──────────────────────────

  private async getEnrichmentContext(
    taskType: string,
    customerId: string,
    agentId: string,
    mode: GatewayMode,
  ): Promise<EnrichmentContext> {
    // Bootstrap mode — no enrichment needed
    if (mode === 'bootstrap') {
      return {
        taskType,
        customerId,
        agentId,
        mode,
        scores: [],
        policyDecision: null,
      };
    }

    try {
      const [scores, policyDecision] = await Promise.all([
        this.scoreFetcher.getScores(taskType, customerId, agentId),
        this.liApi.getPolicyDecision(taskType, customerId, agentId),
      ]);

      return { taskType, customerId, agentId, mode, scores, policyDecision };
    } catch (err) {
      log.warn('Enrichment context fetch failed — degrading to bootstrap-like', {
        error: err instanceof Error ? err.message : String(err),
      });
      return {
        taskType,
        customerId,
        agentId,
        mode,
        scores: [],
        policyDecision: null,
      };
    }
  }

  // ── Private: routing helpers ─────────────────────────────

  private resolveUpstream(toolName: string): string {
    const entries = this.registry.getAllUpstreams();

    // Match tool name to upstream by prefix convention:
    // "github_push_fix" → upstream named "github"
    // "database_query" → upstream named "database"
    const prefix = toolName.split('_')[0];
    if (prefix) {
      const matched = entries.find(
        (e) => e.server.name === prefix && this.registry.isHealthy(e.server.name),
      );
      if (matched) return matched.server.name;
    }

    // Fallback: first healthy upstream
    for (const entry of entries) {
      if (this.registry.isHealthy(entry.server.name)) return entry.server.name;
    }
    return entries[0]?.server.name ?? 'unknown';
  }

  private async logDecision(record: {
    decisionId: string;
    agentId: string;
    customerId: string;
    taskType: string;
    actionName: string;
    upstreamName: string;
    originalAction: string;
    executedAction: string;
    mode: GatewayMode;
    rerouted: boolean;
    enrichmentScores: Record<string, number>;
    latencyMs: number;
  }): Promise<void> {
    try {
      // Build API-compatible payload. Omit decision_id — the gateway's
      // dec_ format is non-UUID and the API's schema accepts UUID only.
      const payload: OutcomePayload = {
        agent_id: record.agentId,
        customer_id: record.customerId,
        issue_type: record.taskType,
        action_name: record.actionName,
        upstream_name: record.upstreamName,
        original_action: record.originalAction,
        executed_action: record.executedAction,
        mode: record.mode,
        rerouted: record.rerouted,
        success: true,
        response_time_ms: record.latencyMs,
        timestamp: new Date().toISOString(),
        ingestion_source: 'mcp',
        environment: this.config.environment,
      };

      const sent = await this.liApi.logOutcome(payload);
      if (!sent) {
        await enqueueOutcome(payload);
      }
    } catch {
      // Fire-and-forget — silent failure is acceptable
      log.debug('Outcome logging skipped (non-critical)');
    }
  }
}

/**
 * LayerInfinite MCP Server — types.ts
 * ══════════════════════════════════════════════════════════════
 * Shared domain types for the V2 Gateway Proxy.
 * Imports config types from config.ts; defines gateway-specific types here.
 * ══════════════════════════════════════════════════════════════
 */

import type { LIMode } from './config.js';

/** Gateway operating mode (bootstrap = mode null, observe only). */
export type GatewayMode = 'bootstrap' | LIMode;

/** Enriched tool returned by tools/list interception. */
export interface EnrichedTool {
  name: string;
  /** ENRICHED description — original woven with historical context. Never modify inputSchema. */
  description: string;
  /** UNMODIFIED — passthrough from upstream. */
  inputSchema: Record<string, unknown>;
  /** Which upstream server owns this tool. */
  upstreamName: string;
  annotations?: {
    /** 1-based rank within task (best=1). */
    ranking?: number;
    category?: 'recommended' | 'neutral' | 'warning';
  };
}

/** Context gathered before enriching tool descriptions. */
export interface EnrichmentContext {
  taskType: string;
  customerId: string;
  agentId: string;
  mode: GatewayMode;
  scores: ScoredAction[];
  policyDecision: PolicyDecision | null;
}

/** A scored action from the LI scoring engine. */
export interface ScoredAction {
  actionName: string;
  compositeScore: number;
  successRate: number;
  sampleSize: number;
  trendLabel?: string;
}

/** Policy decision from the LI policy engine. */
export interface PolicyDecision {
  action: string;
  reason: string;
  confidence: number;
}

/** A decision record — one tool invocation tracked by the gateway. */
export interface DecisionRecord {
  /** Format: dec_{ts12}_{agent4}_{rand4} — lexicographically sortable. */
  decisionId: string;
  agentId: string;
  customerId: string;
  taskType: string;
  actionName: string;
  upstreamName: string;
  /** What the agent chose. */
  originalAction: string;
  /** What actually ran (may differ in Auto mode). */
  executedAction: string;
  mode: GatewayMode;
  rerouted: boolean;
  enrichmentScores: Record<string, number>;
  /** ISO 8601 timestamp. */
  timestamp: string;
}

/** An episode — a session containing multiple decisions. */
export interface Episode {
  episodeId: string;
  agentId: string;
  sessionStart: string;
  /** Ordered list of decisionIds. */
  decisions: string[];
  /** Max 3 coachings per episode. */
  coachingCount: number;
}

/** Webhook callback from Layer 2 (session) or Layer 3 (business). */
export interface WebhookCallback {
  decisionId: string;
  /** 2 = session outcome, 3 = business outcome. */
  layer: 2 | 3;
  success: boolean;
  reason?: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/** In-memory fail-open state for circuit breaker + health tracking. */
export interface FailOpenState {
  upstreamFailures: Map<string, number>;
  circuitBreakerOpen: Map<string, boolean>;
  lastHealthCheck: Map<string, number>;
  totalRequests: number;
  passthroughRequests: number;
}

/** Outcome payload sent to LI API for logging. Fields match the API's LogOutcomeBody schema. */
export interface OutcomePayload {
  /** Internal decision ID (dec_ format) — NOT sent to API (API expects UUID). */
  decision_id?: string;
  agent_id: string;
  customer_id: string;
  /** Maps to API's `issue_type` field. */
  issue_type: string;
  action_name: string;
  upstream_name: string;
  original_action: string;
  executed_action: string;
  mode: string;
  rerouted: boolean;
  /** Required by API. Defaults to true for fire-and-forget gateway logging. */
  success: boolean;
  /** Maps to API's `response_time_ms` field. */
  response_time_ms: number;
  timestamp: string;
  ingestion_source: 'mcp';
  environment: string;
}

/**
 * LayerInfinite API — routes/business-webhook.ts
 * ══════════════════════════════════════════════════════════════
 * POST /v1/webhook/callback — Business outcome webhook endpoint.
 *
 * Receives Layer 2 (session) and Layer 3 (business) outcome signals
 * linked via decision_id. Validates HMAC signature, resolves the
 * original outcome, and orchestrates the 3-layer score overwrite.
 *
 * Idempotent: duplicate (decision_id + layer) → 200 (replayed).
 * ══════════════════════════════════════════════════════════════
 */

import { Context } from 'hono';
import { z } from 'zod';
import {
  verifyBusinessWebhook,
  isTimestampValid,
  checkRateLimit,
} from '../lib/webhook-verifier.js';
import { handleWebhookCallback } from '../lib/outcome-orchestrator.js';

// ── Request schema ───────────────────────────────────────────

const WebhookCallbackBody = z.object({
  decision_id: z.string().min(1).max(255),
  layer: z
    .number()
    .int()
    .refine((v) => v === 2 || v === 3, { message: 'layer must be 2 (session) or 3 (business)' }),
  success: z.boolean(),
  score: z
    .number()
    .min(0)
    .max(1)
    .default(0.5),
  reason: z.string().max(500).optional(),
  metadata: z.record(z.string(), z.unknown()).optional(),
  timestamp: z.string().datetime().optional(),
});

// ── POST /v1/webhook/callback ────────────────────────────────

export default async function businessWebhookRoute(c: Context): Promise<Response> {
  // ── 1. Rate limit ─────────────────────────────────────────
  const customerId = c.get('customer_id') as string | undefined;
  if (customerId && !checkRateLimit(customerId)) {
    return c.json(
      { error: 'Rate limit exceeded', code: 'RATE_LIMITED', retry_after_ms: 60_000 },
      429,
    );
  }

  // ── 2. Parse body ─────────────────────────────────────────
  let body: z.infer<typeof WebhookCallbackBody>;
  try {
    body = WebhookCallbackBody.parse(await c.req.json());
  } catch (err: any) {
    const details = err.errors
      ? err.errors.map((e: any) => `${e.path.join('.')}: ${e.message}`).join(', ')
      : err.message;
    return c.json({ error: 'Invalid request body', details, code: 'VALIDATION_ERROR' }, 400);
  }

  // ── 3. Verify webhook signature ───────────────────────────
  // HMAC verification is always enforced except when the explicit
  // LI_WEBHOOK_DEV_BYPASS flag is set (local development only).
  if (process.env.LI_WEBHOOK_DEV_BYPASS !== 'true') {
    const rawBody = JSON.stringify(body);
    const signatureHeader = c.req.header('X-LI-Webhook-Signature');

    if (!customerId) {
      return c.json({ error: 'Missing customer context', code: 'MISSING_CUSTOMER_ID' }, 401);
    }

    const verified = await verifyBusinessWebhook(rawBody, signatureHeader, customerId);
    if (!verified) {
      return c.json({ error: 'Invalid webhook signature', code: 'UNAUTHORIZED' }, 401);
    }
  }

  // ── 4. Validate timestamp (if provided in header) ─────────
  const headerTimestamp = c.req.header('X-LI-Webhook-Timestamp');
  if (headerTimestamp) {
    const ts = Number(headerTimestamp);
    if (Number.isFinite(ts) && !isTimestampValid(ts)) {
      return c.json(
        { error: 'Webhook timestamp expired (>24h old or in the future)', code: 'TIMESTAMP_EXPIRED' },
        400,
      );
    }
  }

  // ── 5. Process callback via orchestrator ──────────────────
  try {
    const result = await handleWebhookCallback({
      decisionId: body.decision_id,
      layer: body.layer as 2 | 3,
      success: body.success,
      score: body.score,
      reason: body.reason,
      metadata: body.metadata,
      timestamp: body.timestamp ?? new Date().toISOString(),
    });

    if (!result.resolved) {
      return c.json(
        {
          resolved: false,
          decision_id: body.decision_id,
          message: 'No outcome found for the given decision_id. The outcome may not have been logged yet.',
          code: 'DECISION_NOT_FOUND',
        },
        200,
      );
    }

    const statusCode = result.idempotent ? 200 : 202;

    return c.json(
      {
        resolved: true,
        outcome_id: result.outcomeId,
        decision_id: body.decision_id,
        layer: result.layer,
        previous_score: result.previousScore,
        new_score: result.newScore,
        idempotent_replay: result.idempotent,
        message: result.idempotent
          ? 'Webhook callback already processed (idempotent replay).'
          : 'Webhook callback accepted. Score overwrite applied.',
      },
      statusCode,
    );
  } catch (err: any) {
    console.error('[business-webhook] callback processing failed:', err.message);
    return c.json(
      { error: 'Failed to process webhook callback', details: err.message, code: 'PROCESSING_ERROR' },
      500,
    );
  }
}

import { Context } from 'hono';
import { supabase } from '../lib/supabase.js';
import {
    verifySendgridSignature,
    verifySharedSecret,
    verifyStripeSignature,
} from '../lib/webhook-auth.js';

type Provider = 'stripe' | 'sendgrid' | 'generic';
type BusinessOutcome = 'resolved' | 'partial' | 'failed' | 'unknown';

interface CanonicalWebhookPayload {
    outcomeId: string;
    finalScore: number;
    businessOutcome: BusinessOutcome;
}

function clamp01(value: number): number {
    if (value < 0) return 0;
    if (value > 1) return 1;
    return value;
}

function getObject(value: unknown): Record<string, unknown> {
    if (value && typeof value === 'object' && !Array.isArray(value)) {
        return value as Record<string, unknown>;
    }
    return {};
}

function extractStripePayload(payloadInput: unknown): CanonicalWebhookPayload | null {
    const payload = getObject(payloadInput);
    const eventData = getObject(payload.data);
    const eventObject = getObject(eventData.object);
    const objectPayload = Object.keys(eventObject).length > 0 ? eventObject : payload;

    const metadata = getObject(objectPayload.metadata);
    const outcomeId = metadata.layerinfinite_outcome_id;
    const amountRefunded = Number(objectPayload.amount_refunded ?? 0);
    const amount = Number(objectPayload.amount ?? objectPayload.amount_received ?? 0);
    const eventType = String(payload.type ?? objectPayload.status ?? '').toLowerCase();

    if (typeof outcomeId !== 'string') return null;

    let finalScore = 0.5;
    let businessOutcome: BusinessOutcome = 'unknown';

    if (Number.isFinite(amount) && amount > 0 && Number.isFinite(amountRefunded) && amountRefunded > 0) {
        finalScore = clamp01(amountRefunded / amount);
        businessOutcome = finalScore >= 1 ? 'resolved' : 'partial';
    } else if (
        eventType.includes('succeeded')
        || eventType.includes('completed')
        || eventType.includes('paid')
    ) {
        finalScore = 1.0;
        businessOutcome = 'resolved';
    } else if (
        eventType.includes('failed')
        || eventType.includes('canceled')
        || eventType.includes('expired')
    ) {
        finalScore = 0.0;
        businessOutcome = 'failed';
    }

    return { outcomeId, finalScore, businessOutcome };
}

function extractSendgridPayload(payloadInput: unknown): CanonicalWebhookPayload | null {
    const events = Array.isArray(payloadInput) ? payloadInput : [payloadInput];

    for (const eventRow of events) {
        const eventPayload = getObject(eventRow);
        if (Object.keys(eventPayload).length === 0) continue;

        const customArgs = getObject(eventPayload.custom_args);
        const uniqueArgs = getObject(eventPayload.unique_args);
        const outcomeId = customArgs.outcome_id ?? uniqueArgs.outcome_id;
        const event = String(eventPayload.event ?? '').toLowerCase();

        if (typeof outcomeId !== 'string') {
            continue;
        }

        if (event === 'delivered' || event === 'processed') {
            return { outcomeId, finalScore: 1.0, businessOutcome: 'resolved' };
        }

        if (
            event === 'bounce'
            || event === 'blocked'
            || event === 'dropped'
            || event === 'deferred'
            || event === 'spamreport'
        ) {
            return { outcomeId, finalScore: 0.0, businessOutcome: 'failed' };
        }

        return { outcomeId, finalScore: 0.5, businessOutcome: 'unknown' };
    }

    return null;
}

function extractGenericPayload(payloadInput: unknown): CanonicalWebhookPayload | null {
    const payload = getObject(payloadInput);
    const outcomeId = payload.outcome_id;
    const finalScore = Number(payload.final_score);
    const businessOutcome = String(payload.business_outcome) as BusinessOutcome;

    const allowedOutcomes = ['resolved', 'partial', 'failed', 'unknown'];
    if (typeof outcomeId !== 'string') return null;
    if (Number.isNaN(finalScore)) return null;
    if (!allowedOutcomes.includes(businessOutcome)) return null;

    return {
        outcomeId,
        finalScore: clamp01(finalScore),
        businessOutcome,
    };
}

function extractPayload(provider: Provider, payloadInput: unknown): CanonicalWebhookPayload | null {
    if (provider === 'stripe') return extractStripePayload(payloadInput);
    if (provider === 'sendgrid') return extractSendgridPayload(payloadInput);
    return extractGenericPayload(payloadInput);
}

function isWebhookAuthorized(params: {
    provider: Provider;
    c: Context;
    rawBody: string;
}): boolean {
    const sharedSecret = process.env.LI_WEBHOOK_SHARED_SECRET;
    const providedSharedSecret = params.c.req.header('x-layerinfinite-webhook-secret');

    if (verifySharedSecret(sharedSecret, providedSharedSecret)) {
        return true;
    }

    if (params.provider === 'stripe') {
        const stripeSigningSecret = process.env.STRIPE_WEBHOOK_SIGNING_SECRET;
        const stripeSignature = params.c.req.header('stripe-signature');
        const tolerance = Number(process.env.STRIPE_WEBHOOK_TOLERANCE_SECONDS ?? 300);

        if (verifyStripeSignature(params.rawBody, stripeSignature, stripeSigningSecret, tolerance)) {
            return true;
        }
    }

    if (params.provider === 'sendgrid') {
        const sendgridPublicKey = process.env.SENDGRID_EVENT_WEBHOOK_PUBLIC_KEY;
        const sendgridSignature = params.c.req.header('x-twilio-email-event-webhook-signature');
        const sendgridTimestamp = params.c.req.header('x-twilio-email-event-webhook-timestamp');

        if (verifySendgridSignature(params.rawBody, sendgridTimestamp, sendgridSignature, sendgridPublicKey)) {
            return true;
        }
    }

    // Explicit dev bypass — set LI_WEBHOOK_DEV_BYPASS=true only for local testing.
    // All deployed environments (staging, production) enforce auth.
    if (process.env.LI_WEBHOOK_DEV_BYPASS === 'true') {
        return true;
    }

    return false;
}

export default async function webhookRoute(c: Context): Promise<Response> {
    try {
        const provider = c.req.param('provider') as Provider;
        if (!['stripe', 'sendgrid', 'generic'].includes(provider)) {
            return c.json({ resolved: false }, 200);
        }

        const rawBody = await c.req.text();

        if (!isWebhookAuthorized({ provider, c, rawBody })) {
            return c.json({ resolved: false }, 401);
        }

        let parsedPayload: unknown;
        try {
            parsedPayload = JSON.parse(rawBody);
        } catch {
            return c.json({ resolved: false }, 200);
        }

        const payload = extractPayload(provider, parsedPayload);

        if (!payload) {
            return c.json({ resolved: false }, 200);
        }

        const { data: pending } = await supabase
            .from('dim_pending_signal_registrations')
            .select('registration_id, customer_id, resolved, event_type, platform')
            .eq('outcome_id', payload.outcomeId)
            .eq('platform', provider)
            .eq('resolved', false)
            .limit(1)
            .maybeSingle();

        if (!pending) {
            return c.json({ resolved: false, outcome_id: payload.outcomeId }, 200);
        }

        const { data: currentOutcome } = await supabase
            .from('fact_outcomes')
            .select('outcome_id, success')
            .eq('outcome_id', payload.outcomeId)
            .eq('customer_id', pending.customer_id)
            .limit(1)
            .maybeSingle();

        if (!currentOutcome) {
            return c.json({ resolved: false, outcome_id: payload.outcomeId }, 200);
        }

        const finalSignalSuccess = payload.finalScore >= 0.5;
        const crossEventStatus = currentOutcome.success === finalSignalSuccess
            ? 'confirmed'
            : 'conflict';
        const nowIso = new Date().toISOString();

        const { error: outcomeUpdateError } = await supabase
            .from('fact_outcomes')
            .update({
                outcome_score: payload.finalScore,
                business_outcome: payload.businessOutcome,
                feedback_received_at: nowIso,
                signal_pending: false,
                signal_updated_at: nowIso,
                cross_event_status: crossEventStatus,
                cross_event_last_updated: nowIso,
                pending_registration_id: pending.registration_id,
            })
            .eq('outcome_id', payload.outcomeId)
            .eq('customer_id', pending.customer_id);

        if (outcomeUpdateError) {
            return c.json({ resolved: false, outcome_id: payload.outcomeId }, 200);
        }

        await supabase
            .from('dim_pending_signal_registrations')
            .update({
                resolved: true,
                resolved_at: nowIso,
                resolved_by: `${provider}_webhook`,
            })
            .eq('registration_id', pending.registration_id)
            .eq('customer_id', pending.customer_id);

        if (crossEventStatus === 'conflict') {
            const { data: existingConflict } = await supabase
                .from('dim_discrepancy_log')
                .select('discrepancy_id')
                .eq('customer_id', pending.customer_id)
                .eq('outcome_id', payload.outcomeId)
                .eq('discrepancy_type', 'cross_event_conflict')
                .eq('resolved', false)
                .limit(1);

            if (!existingConflict || existingConflict.length === 0) {
                await supabase
                    .from('dim_discrepancy_log')
                    .insert({
                        customer_id: pending.customer_id,
                        outcome_id: payload.outcomeId,
                        registration_id: pending.registration_id,
                        action_name: `${pending.platform}:${pending.event_type}`,
                        discrepancy_type: 'cross_event_conflict',
                        expected_outcome: currentOutcome.success,
                        actual_outcome: finalSignalSuccess,
                        signal_confidence: payload.finalScore,
                        detail:
                            `Webhook ${provider} contradicted initial outcome polarity. ` +
                            `initial_success=${String(currentOutcome.success)} final_score=${payload.finalScore.toFixed(4)}.`,
                    });
            }
        }

        return c.json({
            resolved: true,
            outcome_id: payload.outcomeId,
            cross_event_status: crossEventStatus,
        }, 200);
    } catch {
        return c.json({ resolved: false }, 200);
    }
}

